    import sys
    input = sys.stdin.read
    data = input().split()
    idx = 0
    N = int(data[idx])
    idx += 1
    H = int(data[idx])
    idx += 1
    W = int(data[idx])
    idx += 1
    tiles = []
    for _ in range(N):
        a = int(data[idx])
        idx += 1
        b = int(data[idx])
        idx += 1
        tiles.append((a, b))

    def is_valid(grid, i, j, x, y, h, w):
        if i + x > h or j + y > w:
            return False
        for dx in range(x):
            for dy in range(y):
                if grid[i + dx][j + dy]:
                    return False
        return True

    def backtrack(tiles, grid, h, w):
        for i in range(h):
            for j in range(w):
                if not grid[i][j]:
                    for idx_tile in range(len(tiles)):
                        a, b = tiles[idx_tile]
                        for x, y in [(a, b), (b, a)]:
                            if is_valid(grid, i, j, x, y, h, w):
                                for dx in range(x):
                                    for dy in range(y):
                                        grid[i + dx][j + dy] = True
                                new_tiles = tiles[:idx_tile] + tiles[idx_tile+1:]
                                if backtrack(new_tiles, grid, h, w):
                                    return True
                                for dx in range(x):
                                    for dy in range(y):
                                        grid[i + dx][j + dy] = False
                    return False
        return True

    for mask in range(1 << N):
        subset = []
        for i in range(N):
            if (mask >> i) & 1:
                subset.append(tiles[i])
        sum_area = sum(a * b for a, b in subset)
        if sum_area != H * W:
            continue
        grid = [[False] * W for _ in range(H)]
        if backtrack(subset, grid, H, W):
            print("Yes")
            return
    print("No")

