def main():
    H, W = map(int, sys.stdin.readline().split())
    grid = [sys.stdin.readline().strip() for _ in range(H)]

    # Precompute safe cells
    safe = [[False]*W for _ in range(H)]
    for i in range(H):
        for j in range(W):
            is_safe = True
            for dx, dy in [(-1,0), (1,0), (0,-1), (0,1)]:
                ni = i + dx
                nj = j + dy
                if 0 <= ni < H and 0 <= nj < W:
                    if grid[ni][nj] == '#':
                        is_safe = False
                        break
            safe[i][j] = is_safe

    visited = [[False]*W for _ in range(H)]
    max_freedom = 1  # At least one cell without a magnet

    for i in range(H):
        for j in range(W):
            if safe[i][j] and not visited[i][j]:
                # BFS to find component
                q = deque()
                q.append((i, j))
                visited[i][j] = True
                component = set()
                component.add((i, j))
                while q:
                    x, y = q.popleft()
                    for dx, dy in [(-1,0), (1,0), (0,-1), (0,1)]:
                        nx = x + dx
                        ny = y + dy
                        if 0 <= nx < H and 0 <= ny < W:
                            if safe[nx][ny] and not visited[nx][ny]:
                                visited[nx][ny] = True
                                component.add((nx, ny))
                                q.append((nx, ny))
                # Compute A for this component
                adj_cells = set()
                for (x, y) in component:
                    for dx, dy in [(-1,0), (1,0), (0,-1), (0,1)]:
                        nx = x + dx
                        ny = y + dy
