class Solution:
    def maximumLengthSubstring(self, s: str) -> int:
        from collections import defaultdict
        count = defaultdict(int)
        left = 0
        max_len = 0
        for right in range(len(s)):
            count[s[right]] += 1
            while count[s[right]] > 2:
                count[s[left]] -= 1
                left += 1
            current_len = right - left + 1
            if current_len > max_len:
                max_len = current_len
        return max_len

