class Solution:
    def minimumDistance(self, points: List[List[int]]) -> int:
        n = len(points)
        s_list = [x + y for x, y in points]
        d_list = [x - y for x, y in points]

        def get_max_and_second(arr):
            max1 = -float('inf')
            max2 = -float('inf')
            for num in arr:
                if num > max1:
                    max2 = max1
                    max1 = num
                elif num > max2:
                    max2 = num
            return max1, max2

        def get_min_and_second(arr):
            min1 = float('inf')
            min2 = float('inf')
            for num in arr:
                if num < min1:
                    min2 = min1
                    min1 = num
                elif num < min2:
                    min2 = num
            return min1, min2

        max1_s, max2_s = get_max_and_second(s_list)
        min1_s, min2_s = get_min_and_second(s_list)
        count_max_s = s_list.count(max1_s)
        count_min_s = s_list.count(min1_s)

        max1_d, max2_d = get_max_and_second(d_list)
        min1_d, min2_d = get_min_and_second(d_list)
        count_max_d = d_list.count(max1_d)
        count_min_d = d_list.count(min1_d)

        res = float('inf')
        for i in range(n):
            x, y = points[i]
            s_i = x + y
            d_i = x - y

            # Calculate new_max_s and new_min_s
            if s_i == max1_s:
                if count_max_s > 1:
                    new_max_s = max1_s
                else:
                    new_max_s = max2_s
            else:
                new_max_s = max1_s

            if s_i == min1_s:
                if count_min_s > 1:
                    new_min_s = min1_s
                else:
                    new_min_s = min2_s
            else:
                new_min_s = min1_s

            # Calculate new_max_d and new_min_d
            if d_i == max1_d:
                if count_max_d > 1:
                    new_max_d = max1_d
                else:
                    new_max_d = max2_d
            else:
                new_max_d = max1_d

            if d_i == min1_d:
                if count_min_d > 1:
                    new_min_d = min1_d
                else:
                    new_min_d = min2_d
            else:
                new_min_d = min1_d

            current_max = max(new_max_s - new_min_s, new_max_d - new_min_d)
            res = min(res, current_max)

        return res

