class Solution:
    def longestMonotonicSubarray(self, nums: List[int]) -> int:
        max_len = 1
        n = len(nums)
        for i in range(n):
            for j in range(i, n):
                is_incr = True
                is_decr = True
                for k in range(i, j):
                    if nums[k] >= nums[k + 1]:
                        is_incr = False
                    if nums[k] <= nums[k + 1]:
                        is_decr = False
                if is_incr or is_decr:
