class Solution:
    def findKthSmallest(self, coins: List[int], k: int) -> int:
        min_coin = min(coins)
        low = 1
        high = k * min_coin

        while low <= high:
            mid = (low + high) // 2
            total = 0
            n = len(coins)
            for mask in range(1, 1 << n):
                subset_coins = []
                for i in range(n):
                    if mask & (1 << i):
                        subset_coins.append(coins[i])
                # Compute LCM of subset_coins
                lcm = 1
                valid = True
                for coin in subset_coins:
                    gcd_val = math.gcd(lcm, coin)
                    lcm = (lcm * coin) // gcd_val
                    if lcm > mid:
                        valid = False
                        break
                if not valid:
                    continue
                m = len(subset_coins)
                if m % 2 == 1:
                    total += mid // lcm
                else:
                    total -= mid // lcm
            if total >= k:
                high = mid - 1
            else:
                low = mid + 1
        return low

