class Solution:
    def minAnagramLength(self, s: str) -> int:
        from collections import Counter

        n = len(s)
        count = Counter(s)

        def get_divisors(n):
            divisors = set()
            for i in range(1, int(n**0.5) + 1):
                if n % i == 0:
                    divisors.add(i)
                    divisors.add(n // i)
            return sorted(divisors)

        divisors = get_divisors(n)

        for d in divisors:
            k = n // d
            # Check if all character counts are divisible by k
            valid = True
            for c in count:
                if count[c] % k != 0:
                    valid = False
                    break
            if not valid:
                continue
            # Compute target frequency list
            target_list = [0] * 26
            for c in count:
                target_list[ord(c) - ord('a')] = count[c] // k
            # Check all parts
            valid_parts = True
            for i in range(k):
                part = s[i * d : (i + 1) * d]
                part_count = [0] * 26
                for c in part:
                    part_count[ord(c) - ord('a')] += 1
                for j in range(26):
                    if part_count[j] != target_list[j]:
                        valid_parts = False
                        break
                if not valid_parts:
                    break
            if valid_parts:
                return d
        return n

