class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        MOD = 10**9 + 7
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def dp(z, o, last, run):
            if z == zero and o == one:
                return 1
            res = 0
            # Try adding the same element if possible
            if last == 0:
                if run + 1 <= limit and z + 1 <= zero:
                    res += dp(z + 1, o, 0, run + 1)
            else:
                if run + 1 <= limit and o + 1 <= one:
                    res += dp(z, o + 1, 1, run + 1)
            # Try adding the other element
            if last == 0:
                if o + 1 <= one:
                    res += dp(z, o + 1, 1, 1)
            else:
                if z + 1 <= zero:
                    res += dp(z + 1, o, 0, 1)
            return res % MOD

        total = 0
        # Start with 0
        if zero >= 1:
            total += dp(1, 0, 0, 1)
        # Start with 1
        if one >= 1:
            total += dp(0, 1, 1, 1)
        return total % MOD

